@app.route("/login")
def login():
    if not OIDC_AUTHORIZATION_ENDPOINT or not OIDC_CLIENT_ID:
        abort(500, description="OIDC configuration is incomplete")

    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    session["oidc_state"] = state
    session["oidc_nonce"] = nonce

    params = {
        "response_type": "code",
        "client_id": OIDC_CLIENT_ID,
        "redirect_uri": OIDC_REDIRECT_URI,
        "scope": OIDC_SCOPES,
        "state": state,
        "nonce": nonce,
    }

    authorization_url = f"{OIDC_AUTHORIZATION_ENDPOINT}?{urllib.parse.urlencode(params)}"
    return redirect(authorization_url)


@app.route("/callback")
def callback():
    error = request.args.get("error")
    if error:
        return jsonify(
            {
                "error": error,
                "error_description": request.args.get("error_description"),
            }
        ), 400

    code = request.args.get("code")
    state = request.args.get("state")
    expected_state = session.get("oidc_state")

    if not code or not state or state != expected_state:
        return jsonify({"error": "Invalid authorization response"}), 400

    if not OIDC_TOKEN_ENDPOINT or not OIDC_CLIENT_SECRET:
        abort(500, description="OIDC configuration is incomplete")

    token_response = requests.post(
        OIDC_TOKEN_ENDPOINT,
        data={
            "grant_type": "authorization_code",
            "code": code,
            "redirect_uri": OIDC_REDIRECT_URI,
            "client_id": OIDC_CLIENT_ID,
            "client_secret": OIDC_CLIENT_SECRET,
        },
        headers={"Accept": "application/json"},
        timeout=10,
    )

    if token_response.status_code != 200:
        return jsonify(
            {
                "error": "Token exchange failed",
                "details": token_response.text,
            }
        ), 400

    tokens = token_response.json()
    id_token = tokens.get("id_token")
    access_token = tokens.get("access_token")

    if not id_token:
        return jsonify({"error": "No id_token received"}), 400

    try:
        claims = decode_jwt_unverified(id_token)
        validate_id_token_claims(claims)
    except Exception as exc:
        return jsonify({"error": "Invalid id_token", "details": str(exc)}), 400

    session["user"] = {
        "sub": claims.get("sub"),
        "name": claims.get("name"),
        "email": claims.get("email"),
        "preferred_username": claims.get("preferred_username"),
        "claims": claims,
    }
    session["tokens"] = {
        "access_token": access_token,
        "id_token": id_token,
        "token_type": tokens.get("token_type"),
        "expires_in": tokens.get("expires_in"),
        "scope": tokens.get("scope"),
        "refresh_token": tokens.get("refresh_token"),
    }

    session.pop("oidc_state", None)
    session.pop("oidc_nonce", None)

    return redirect(url_for("profile"))


@app.route("/profile")
def profile():
    user = session.get("user")
    if not user:
        return redirect(url_for("login"))
    return jsonify(user)


@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("index"))


